var val = Services.getValue(RecognizanceSum.dataBinding);
var err = validateCurrencyValue(val, 99999999.99);
if( null == err )
{	Services.setValue(RecognizanceSum.dataBinding, WPU.formatToTwoDP(val));
}
return err;

